sub hash_object {
    my $file = shift;
    open my $fh, '<', $file or die "fatal: could not open '$file' for reading: $!\n";
    my $content = do { local $/; <$fh> };
    close $fh;
    my $sha = sha1_hex($content);
    my $dir = ".git/objects/" . substr($sha, 0, 2);
    my $path = "$dir/" . substr($sha, 2);
    make_path($dir) unless -d $dir;
    open my $out, '>', $path or die "fatal: could not create object file: $!\n";
    print $out $content;
    close $out;
    print "$sha\n";
}

